   Value *BOp0 = BO->getOperand(0), *BOp1 = BO->getOperand(1);
+  LLVM_DEBUG(dbgs() << "foldICmpBinOpEqualityWithConstant: " << Cmp << "\n");

   switch (BO->getOpcode()) {
   case Instruction::SRem:
