     }
     break;
   case Instruction::Add: {
+    LLVM_DEBUG(dbgs() << "InstCombine: icmp with add, checking patterns\n");
     // (A + C2) == C --> A == (C - C2)
     // (A + C2) != C --> A != (C - C2)
     // TODO: Remove the one-use limitation? See discussion in D58633.
     if (Constant *C2 = dyn_cast<Constant>(BOp1)) {
       if (BO->hasOneUse())
         return new ICmpInst(Pred, BOp0, ConstantExpr::getSub(RHS, C2));
-    } else if (C.isZero()) {
+    }
+    // If both operands are zext of i1, the sum is in {0,1,2}.
+    LLVM_DEBUG(dbgs() << "BOp0: " << *BOp0 << " BOp1: " << *BOp1 << "\n");
+    Value *X, *Y;
+    if (match(BOp0, m_ZExt(m_Value(X))) && X->getType()->isIntOrIntVectorTy(1) &&
+        match(BOp1, m_ZExt(m_Value(Y))) && Y->getType()->isIntOrIntVectorTy(1)) {
+      LLVM_DEBUG(dbgs() << "InstCombine: folding add of two zext i1 to xor/and/or\n");
+      // (zext i1 X) + (zext i1 Y) == 0 --> !X & !Y
+      // (zext i1 X) + (zext i1 Y) == 1 --> X ^ Y
+      // (zext i1 X) + (zext i1 Y) == 2 --> X & Y
+      // For !=, invert the logic.
+      bool IsNE = Pred == ICmpInst::ICMP_NE;
+      // Sum of two booleans cannot exceed 2.
+      if (C.uge(3))
+        return replaceInstUsesWith(Cmp, ConstantInt::getBool(Cmp.getType(), IsNE));
+      Value *Result;
+      if (C.isZero()) {
+        // Both false.
+        Value *Or = Builder.CreateOr(X, Y);
+        Result = Builder.CreateNot(Or);
+      } else if (C.isOne()) {
+        Result = Builder.CreateXor(X, Y);
+      } else if (C == 2) {
+        Result = Builder.CreateAnd(X, Y);
+      } else {
+        // C == 0,1,2 already covered.
+        llvm_unreachable("C should be 0,1,2 or >=3");
+      }
+      if (IsNE)
+        Result = Builder.CreateNot(Result);
+      return replaceInstUsesWith(Cmp, Result);
+    }
+    // If both operands are sext of i1, the sum is in {-2,-1,0}.
+    if (match(BOp0, m_SExt(m_Value(X))) && X->getType()->isIntOrIntVectorTy(1) &&
+        match(BOp1, m_SExt(m_Value(Y))) && Y->getType()->isIntOrIntVectorTy(1)) {
+      LLVM_DEBUG(dbgs() << "InstCombine: folding add of two sext i1 to xor/and/or\n");
+      // (sext i1 X) + (sext i1 Y) == -2 --> X & Y
+      // (sext i1 X) + (sext i1 Y) == -1 --> X ^ Y
+      // (sext i1 X) + (sext i1 Y) == 0 --> !X & !Y
+      // For !=, invert the logic.
+      bool IsNE = Pred == ICmpInst::ICMP_NE;
+      // Sum of two booleans cannot be outside {-2,-1,0}.
+      if (C.sgt(0) || C.slt(-2))
+        return replaceInstUsesWith(Cmp, ConstantInt::getBool(Cmp.getType(), IsNE));
+      Value *Result;
+      if (C.isZero()) {
+        // Both false.
+        Value *Or = Builder.CreateOr(X, Y);
+        Result = Builder.CreateNot(Or);
+      } else if (C.isAllOnes()) { // -1
+        Result = Builder.CreateXor(X, Y);
+      } else if (C == -2) { // -2
+        Result = Builder.CreateAnd(X, Y);
+      } else {
+        // C == 0,-1,-2 already covered.
+        llvm_unreachable("C should be 0,-1,-2 or out of range");
+      }
+      if (IsNE)
+        Result = Builder.CreateNot(Result);
+      return replaceInstUsesWith(Cmp, Result);
+    }
+    if (C.isZero()) {
